    public function parse(string $inputPath, string $outputPath): void
    {
        $file = fopen($inputPath, 'r');
        stream_set_read_buffer($file, 0);

        $endpoints = [];

        while (($line = fgets($file)) !== false) {
            $endpoint = substr($line, 25, -27);
            $date = substr($line, -26, 10);

            if (!isset($endpoints[$endpoint])) {
                $endpoints[$endpoint] = [];
            }

            if (!isset($endpoints[$endpoint][self::DATE_INDEXES[$date]])) {
                $endpoints[$endpoint][self::DATE_INDEXES[$date]] = 0;
            }

            $endpoints[$endpoint][self::DATE_INDEXES[$date]]++;
        }

        $file = fopen($outputPath, 'w');

        ob_start(function($buffer) use ($file) {
            fwrite($file, $buffer);
            return '';
        });

        $lastCollection = '    "\/blog\/' . array_key_last($endpoints) . "\": {\n";
        $lastVisits = array_pop($endpoints);
        $last = '        "' . self::INDEX_DATES[array_key_last($lastVisits)] . '": ' . array_pop($lastVisits);
        foreach ($lastVisits as $i => $count) {
            $lastCollection .= '        "' . self::INDEX_DATES[$i] . '": ' . $count . ",\n";
        }
        $lastCollection .= $last . "\n    }\n";

        echo "{\n";
        foreach ($endpoints as $endpoint => $visits) {
            ksort($visits);

            $last = '        "' . self::INDEX_DATES[array_key_last($visits)] . '": ' . array_pop($visits);

            echo '    "\/blog\/' . $endpoint . "\": {\n";
            foreach ($visits as $i => $count) {
                echo '        "' . self::INDEX_DATES[$i] . '": ' . $count . ",\n";
            }
            echo $last . "\n    },\n";
        }

        echo $lastCollection . '}';

        ob_end_flush();
    }
